# Thread-Safe Patterns for TouchDesigner
import threading
import queue
from collections import deque

# --- Thread-Safe Result Queue ---
# Background thread posts results; TD main thread reads them each frame

_result_queue = queue.Queue(maxsize=100)
_worker_thread = None

def start_worker():
    global _worker_thread

    def worker():
        while True:
            try:
                # Process work items
                work_item = _work_queue.get(timeout=1.0)
                if work_item is None:
                    break  # shutdown signal

                result = do_heavy_work(work_item)
                _result_queue.put_nowait(result)
            except queue.Empty:
                continue
            except queue.Full:
                pass  # drop result if queue full

    _worker_thread = threading.Thread(target=worker, daemon=True)
    _worker_thread.start()
    print('[Thread] Worker started')

_work_queue = queue.Queue(maxsize=10)

def submit_work(item):
    """Submit work from main TD thread (non-blocking)."""
    try:
        _work_queue.put_nowait(item)
    except queue.Full:
        pass  # drop if worker is busy

def do_heavy_work(item):
    """Runs in background thread — can block freely."""
    import time
    time.sleep(0.01)  # simulate work
    return {'processed': item, 'result': item * 2}

# In Script CHOP cook() — drain results non-blocking:
def cook(scriptOp):
    # Process up to N results per frame
    for _ in range(5):
        try:
            result = _result_queue.get_nowait()
            # Apply result to parameters (safe: we're in main thread)
            scriptOp['output'][0] = result.get('result', 0.0)
        except queue.Empty:
            break


# --- Read-Write Lock for shared data structures ---
class RWLock:
    """Allow multiple concurrent readers or one writer."""
    def __init__(self):
        self._read_ready = threading.Condition(threading.Lock())
        self._readers = 0

    def acquire_read(self):
        with self._read_ready:
            self._readers += 1

    def release_read(self):
        with self._read_ready:
            self._readers -= 1
            if self._readers == 0:
                self._read_ready.notify_all()

    def acquire_write(self):
        self._read_ready.acquire()
        while self._readers > 0:
            self._read_ready.wait()

    def release_write(self):
        self._read_ready.release()


# --- CRITICAL: Schedule UI/parameter changes on main thread ---
def safe_set_param(op_path, param_name, value):
    """
    Safely set a TD parameter from a background thread.
    run() schedules execution on the main cook thread.
    """
    run(f'op("{op_path}").par.{param_name} = {repr(value)}')
